/** Executes the exact-count, ten-seed runtime release campaigns and retains independently checkable evidence. */
@Tag("slow")
class RuntimeCertificationCampaignTest {
	private static final List<Long> SEEDS = List.of(
			0x5905_7101L,
			0x5905_7102L,
			0x5905_7103L,
			0x5905_7104L,
			0x5905_7105L,
			0x5905_7106L,
			0x5905_7107L,
			0x5905_7108L,
			0x5905_7109L,
			0x5905_7110L);

	@Test
	void runRuntimeReleaseCampaigns() throws IOException {
		int randomPairs = Integer.getInteger("equivalence.certification.runtimeRandomPairs", 1_000);
		int rulePairs = Integer.getInteger("equivalence.certification.runtimeRulePairs", 1_000);
		long timeBudgetSeconds = Long.getLong("equivalence.certification.runtimeTimeBudgetSeconds", 21_600L);
		int threads = Integer.getInteger("equivalence.certification.runtimeThreads", 8);
		int chunkSize = Integer.getInteger("equivalence.certification.runtimeChunkSize", 2_000);
		String oracleVersion = System.getProperty("equivalence.certification.runtimeOracleVersion", "");
		assertTrue(randomPairs >= 0 && rulePairs >= 0, "campaign pair counts must be non-negative");
		assertTrue(threads > 0 && chunkSize > 0, "campaign thread and chunk counts must be positive");
		assertTrue(!oracleVersion.isBlank(),
				"runtime campaign must pin equivalence.certification.runtimeOracleVersion");

		Path outputDirectory = Path.of(System.getProperty(
				"equivalence.certification.runtimeOutputDir", "target/certification/runtime"));
		Files.createDirectories(outputDirectory);
		Instant started = Instant.now();
		Instant deadline = started.plusSeconds(timeBudgetSeconds);
		try (BufferedWriter certificateWriter = Files.newBufferedWriter(
				outputDirectory.resolve("certificates.jsonl"),
				StandardCharsets.UTF_8,
				StandardOpenOption.CREATE,
				StandardOpenOption.TRUNCATE_EXISTING);
				BufferedWriter summaryWriter = Files.newBufferedWriter(
						outputDirectory.resolve("summary.csv"),
						StandardCharsets.UTF_8,
						StandardOpenOption.CREATE,
						StandardOpenOption.TRUNCATE_EXISTING)) {
			summaryWriter.write("campaign,oracleVersion,seed,pairs,certificates,elapsedSeconds\n");
			runCampaign("random", randomPairs, deadline, oracleVersion, outputDirectory, threads, chunkSize,
					(seed, count) -> new RandomTreePairSource().pairs(seed, count), certificateWriter, summaryWriter);
			runCampaign("rule-shaped", rulePairs, deadline, oracleVersion, outputDirectory, threads, chunkSize,
					RuntimeCertificationCampaignTest::rulePairs, certificateWriter, summaryWriter);
			summaryWriter.write("TOTAL," + oracleVersion + ",," + ((long) randomPairs + rulePairs) + ",,"
					+ Duration.between(started, Instant.now()).toSeconds() + "\n");
		}
	}

	private static void runCampaign(
			String campaign,
			int totalPairs,
			Instant deadline,
			String oracleVersion,
			Path outputDirectory,
			int threads,
			int chunkSize,
			BiFunction<Long, Integer, List<TreePair>> source,
			BufferedWriter certificateWriter,
			BufferedWriter summaryWriter) throws IOException {
		Path shards = outputDirectory.resolve("certificate-shards").resolve(campaign);
		Files.createDirectories(shards);
		ExecutorService executor = Executors.newFixedThreadPool(Math.min(threads, SEEDS.size()));
		List<Future<SeedResult>> futures = new ArrayList<>();
		try {
			for (int seedIndex = 0; seedIndex < SEEDS.size(); seedIndex++) {
				long seed = SEEDS.get(seedIndex);
				int expected = totalPairs / SEEDS.size() + (seedIndex < totalPairs % SEEDS.size() ? 1 : 0);
				futures.add(executor.submit(() -> runSeed(
						campaign, seed, expected, deadline, outputDirectory, shards, chunkSize, source)));
			}
		} finally {
			executor.shutdown();
		}

		int completed = 0;
		for (Future<SeedResult> future : futures) {
			SeedResult result = await(future);
			completed += result.pairs();
			summaryWriter.write(campaign + "," + oracleVersion + "," + result.seed() + "," + result.pairs() + ","
					+ result.certificates() + "," + result.elapsedSeconds() + "\n");
			try (var shardReader = Files.newBufferedReader(result.certificateShard(), StandardCharsets.UTF_8)) {
				for (String line; (line = shardReader.readLine()) != null;) {
					certificateWriter.write(line);
					certificateWriter.newLine();
				}
			}
			summaryWriter.flush();
			certificateWriter.flush();
		}
		assertEquals(totalPairs, completed, "release campaign did not judge every requested pair");
	}

	private static SeedResult runSeed(
			String campaign,
			long seed,
			int expected,
			Instant deadline,
			Path outputDirectory,
			Path shards,
			int chunkSize,
			BiFunction<Long, Integer, List<TreePair>> source) throws IOException {
		Instant seedStarted = Instant.now();
		int completed = 0;
		int certificates = 0;
		Path certificateShard = shards.resolve("seed-" + seed + ".jsonl");
		try (BufferedWriter writer = Files.newBufferedWriter(
				certificateShard,
				StandardCharsets.UTF_8,
				StandardOpenOption.CREATE,
				StandardOpenOption.TRUNCATE_EXISTING)) {
			while (completed < expected) {
				int count = Math.min(chunkSize, expected - completed);
				List<TreePair> pairs = source.apply(seed + completed, count);
				assertEquals(count, pairs.size(), "pair source returned the wrong release-campaign count");
				Duration remaining = Duration.between(Instant.now(), deadline);
				assertTrue(!remaining.isNegative() && !remaining.isZero(),
						"time budget truncated before " + campaign + " seed " + seed);
				DifferentialFuzzHarness harness = new DifferentialFuzzHarness(
						FuzzProfile.primary(160),
						FuzzProfile.secondary(160),
						new PairShrinker(),
						new FuzzArtifactWriter(
								outputDirectory.resolve("violations").resolve(campaign), seed + completed),
						true);
				FuzzRunSummary result = harness.run(seed + completed, pairs, remaining);
				assertEquals(count, result.pairCount(),
						"time budget truncated " + campaign + " seed " + seed + "; partial campaigns are failures");
				assertTrue(result.violations().isEmpty(),
						() -> campaign + " runtime differential violations:\n" + result.report());
				certificates += writeAcceptedCertificates(pairs, writer);
				completed += result.pairCount();
				writer.flush();
				System.out.println("[runtime-certification] campaign=" + campaign + " seed=" + seed + " completed="
						+ completed + "/" + expected + " certificates=" + certificates);
			}
		}
		return new SeedResult(
				seed, completed, certificates, Duration.between(seedStarted, Instant.now()).toSeconds(),
				certificateShard);
	}

	private static SeedResult await(Future<SeedResult> future) throws IOException {
		try {
			return future.get();
		} catch (InterruptedException interrupted) {
			Thread.currentThread().interrupt();
			throw new AssertionError("runtime release campaign was interrupted", interrupted);
		} catch (ExecutionException failed) {
			Throwable cause = failed.getCause();
			if (cause instanceof IOException io) {
				throw io;
			}
			if (cause instanceof Error error) {
				throw error;
			}
			throw new AssertionError("runtime release campaign seed failed", cause);
		}
	}

	private static int writeAcceptedCertificates(List<TreePair> pairs, BufferedWriter writer) throws IOException {
		FuzzProfile profile = FuzzProfile.primary(160);
		int certificates = 0;
		for (TreePair pair : pairs) {
			EquivalenceResult result = new AlgebraEquivalenceChecker(profile.options())
					.check(pair.original(), pair.candidate());
			if (result.getStatus() == EquivalenceStatus.EQUIVALENT) {
				NormalizationProof proof = assertInstanceOf(
						NormalizationProof.class, result.getEvidence().orElseThrow());
				NormalizationCertificate certificate = proof.getCertificate().orElseThrow();
				assertEquals(SemanticsTarget.RDF4J_RUNTIME, certificate.getSemanticsTarget());
				assertTrue(new ProofKernel(profile.options()).verify(pair.original(), pair.candidate(), proof));
				writer.write(certificate.toJson());
				writer.newLine();
				certificates++;
			}
		}
		return certificates;
	}

	private static List<TreePair> rulePairs(long seed, int count) {
		if (count == 0) {
			return List.of();
		}
		int iterations = Math.max(1, Math.ceilDiv(count - 2, RuleLawPairSource.PAIRS_PER_ITERATION));
		List<TreePair> generated = new RuleLawPairSource().pairs(seed, iterations);
		assertTrue(generated.size() >= count, "rule-law source generated too few pairs");
		return List.copyOf(generated.subList(0, count));
	}

	private record SeedResult(long seed, int pairs, int certificates, long elapsedSeconds, Path certificateShard) {
	}
}
